import os
import smtplib
from email.mime.multipart import MIMEMultipart
from email.mime.text import MIMEText
from email.mime.base import MIMEBase
from email import encoders
from dotenv import load_dotenv

load_dotenv()


def send_notification_email(recipient_email, paper_name, attachments=None):
    sender_email = os.getenv("SMTP_EMAIL")
    sender_password = os.getenv("SMTP_PASSWORD")

    if not sender_password:
        return False, "SMTP password not configured."

    try:
        msg = MIMEMultipart()
        msg["From"] = sender_email
        msg["To"] = recipient_email
        msg["Subject"] = f"Paper Orchestra: {paper_name} is Complete!"

        body = f"""
        <html>
        <body>
            <h2>🎻 Paper Orchestra Notification</h2>
            <p>Great news! Your paper has been successfully generated.</p>
            <p>Check the attachments for the final PDF and LaTeX source.</p>
            <hr>
            <p><small>Generated by Paper Orchestra AI</small></p>
        </body>
        </html>
        """
        msg.attach(MIMEText(body, "html"))

        if attachments:
            for file_path in attachments:
                if os.path.exists(file_path):
                    with open(file_path, "rb") as f:
                        part = MIMEBase("application", "octet-stream")
                        part.set_payload(f.read())
                        encoders.encode_base64(part)
                        part.add_header(
                            "Content-Disposition",
                            f'attachment; filename="{os.path.basename(file_path)}"',
                        )
                        msg.attach(part)
                else:
                    print(f" >> Warning: Attachment file not found: {file_path}")

        with smtplib.SMTP_SSL("smtp.gmail.com", 465) as server:
            server.login(sender_email, sender_password)
            server.send_message(msg)
        return True, "Email sent successfully!"
    except Exception as e:
        return False, str(e)
